scwin.f_OnLoadSet = function (i) {
  console.log('scwin.f_OnLoadSet   ::  ' + i);
  // 증빙종류 확정유무 구분코드 (확정:1/미확정:0)
  // 사업자번호의 과세유형구분코드 또는 여타 이유들로 인해,
  // 증빙종류의 공제/불공제유무가 확정인 경우엔 다른 조건에 의해서도 이를 변경하지 못하도록 구분하기 위한 변수

  let deductfixClsCd = 0;
  let row;
  // ds_txncontents.AddRow();
  // ds_txncontents.NameValue(i,"evidClsCd")      = ds_slip_import.NameValue(i,"evidClsCd");   // 증빙구분코드

  row = ds_txncontents.insertRow();
  ds_txncontents.setRowPosition(i);
  //이걸 바꾸면 change를 타고 Nm 셋팅 bind
  ds_txncontents.setCellData(i, "evidClsCd", ds_slip_import.getCellData(i, "evidClsCd")); // 증빙구분코드
  ds_txncontents.setCellData(i, "evidClsNm", scwin.txt_evidClsNm);
  lc_adjmClsCd.setValue("2");

  // 증빙종류 기본값:공제[1]
  let deductClsCd = "1";
  ds_txncontents.setCellData(i, "deductClsCd", "1");

  // 사업자번호를 조회하고, 해당 사업자번호의 과세유형코드를 나타내준다.
  //lc_taxnCls.BindColVal = taxnCls;

  // 사업자 번호를 입력한다. 
  ds_txncontents.setCellData(i, "crn", ds_slip_import.getCellData(i, "supBusiNo"));
  scwin.f_openPopUp('7', 'T'); // 사업자번호 검색 팝업 : 팝업으로 하여금 해당되는 코드 유무를 검증한다. 
  ds_txncontents.setCellData(i, "txnDt", ds_slip_import.getCellData(i, "eseroSpplyDt")); // 거래일자
  // ds_txncontents.NameValue(i, "acctDeptCd") = '<%=login.getAcctDeptCd()%>';    // 귀속부서코드
  //f_openPopUp( '4', 'T' );                                                     // 부서코드 검색 팝업  : 팝업으로 하여금 해당되는 코드 유무를 검증한다. 

  // 값입력
  ds_txncontents.setCellData(i, "deductClsCd", deductClsCd);
  ds_txncontents.setCellData(i, "deductfixClsCd", deductfixClsCd);
  ds_txncontents.setCellData(i, "spplyAmt", ds_slip_import.getCellData(i, "eseroSupAmt"));
  ds_txncontents.setCellData(i, "vatAmt", ds_slip_import.getCellData(i, "eseroVatAmt"));
  if (ds_txncontents.getCellData(i, "vatAmt") != 0 && ds_txncontents.getCellData(i, "vatAmt") != "") {
    ds_txncontents.setCellData(i, "vatYn", "1");
  }
  ds_txncontents.setCellData(i, "crcCd", ACConstants.KOREA_WON); // 통화코드
  ds_txncontents.setCellData(i, "rltSeq", i); // 구분
  ed_slipDt.setValue(scwin.slipDt);
  $c.gus.cfEnableKeyData($p);
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  $c.gus.cfDisableObjects($p, [lc_deductClsCd, ed_vatAmt, ed_vatDeclarAcctDeptNm, ed_cardNo, ed_cardNm, ed_crn, ed_crnNm, lc_taxnCls, ed_mgntEmpNo, ed_mgntEmpNm, ed_mgntDt, ed_vatCrn, ed_mgntClntNo, ed_mgntClntNm, ed_vehcleNo, ed_vehcleNm, lc_expenseCd, btn_vehcleNo]);
  $c.gus.cfEnableObjects($p, [udc_fromToCalendar1]); // 2026 03 24 누락 수정
  $c.gus.cfDisableObjects($p, [udc_fromToCalendar1]); // 2026 03 24 누락 수정
  /**
  *      cfDisableObjects([lc_deductClsCd, ed_vatAmt, txt_vatDeclarAcctDeptNm, ed_cardNo, txt_cardNm,ed_crn,txt_crnNm, lc_taxnCls, 
      				  ed_mgntTermStDt,img_mgntTermStDt, ed_mgntTermEndDt, img_mgntTermEndDt, ed_mgntDt, ed_mgntEmpNo, txt_mgntEmpNm, 
      				  txt_vatCrn, ed_mgntClntNo, txt_mgntClntNm ,ed_vehcleNo, txt_vehcleNm, lc_expenseCd, img_vehcleNo]);
  * 
  * 
  */
  debugger;
  $c.gus.cfEnableObjects($p, [btn_acctCd, btn_acctDeptCd, btn_adjmClntNo, btn_vatDeclarAcctDeptCd]);
  scwin.f_EnableYn(ds_txncontents.getRowCount());
  if (scwin.vUpperAcctDeptCd == "00130") {
    $c.gus.cfDisableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
    $c.gus.cfEnableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, ed_pchsItemCd, btn_branchCd]);
  } else {
    $c.gus.cfEnableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
    $c.gus.cfDisableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, btn_pchsItemCd, btn_branchCd]);
  }
};
