scwin.f_Add = function () {
  scwin.state = "N";
  scwin.delflag = "N";
  let row;
  if (ds_txncontents.getCellData(ds_txncontents.getRowCount(), "rltSeq") != 0 && ds_txncontents.getCellData(ds_txncontents.getRowCount(), "rltSeq") != null) {
    rltSeq = parseInt(ds_txncontents.getCellData(ds_txncontents.getRowCount(), "rltSeq")) + 1;
  } else {
    rltSeq = rltSeq + 1;
  }
  $c.gus.cfEnableKeyData($p);
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  $c.gus.cfEnableObjects($p, [udc_fromToCalendar1]);
  $c.gus.cfDisableObjects($p, [lc_deductClsCd, ed_vatAmt, ed_vatDeclarAcctDeptNm, ed_cardNo, ed_cardNm, ed_crn, ed_crnNm, lc_taxnCls, udc_fromToCalendar1, ed_mgntDt, ed_mgntEmpNo, ed_mgntEmpNm,
  //ed_mgntTermStDt, btn_mgntTermStDt, ed_mgntTermEndDt, btn_mgntTermEndDt
  ed_vatCrn, ed_mgntClntNo, ed_mgntClntNm, ed_vehcleNo, ed_vehcleNm, lc_expenseCd, btn_vehcleNo]);
  $c.gus.cfEnableObjects($p, [btn_acctCd, btn_acctDeptCd, btn_adjmClntNo, btn_vatDeclarAcctDeptCd]);

  //ds_txncontents.AddRow();
  if (ds_txncontents.getRowCount() <= 0) {
    row = 0;
    ds_txncontents.insertRow(0);
  } else {
    row = ds_txncontents.getRowPosition() + 1;
    ds_txncontents.insertRow(row);
  }
  ds_txncontents.setRowPosition(row);
  scwin.f_EnableYn(ds_txncontents.getRowCount());
  if (scwin.slipKndCd == ACConstants.SLIPKNDCD_SUB_COMPANY_PCHS) {
    // 전표 종류 : 자회사 - 매입전표 이면 '외상매입금'     
    lc_adjmClsCd.setValue("2");
  } else {
    lc_adjmClsCd.setValue("2");
    //lc_adjmClsCd.index=0;   // 정산방법
  }
  lc_evidClsCd.setSelectedIndex(0);
  lc_crcCd.setValue("KRW");
  scwin.txt_vatYn = 1;

  //f_EvidClsCd(0,0,0,0,0,0); 
  //f_AcctCd(0,0,0);
  scwin.txt_rltSeq = rltSeq;
  //lc_evidClsCd.focus();
  if (scwin.vUpperAcctDeptCd == "00130") {
    $c.gus.cfDisableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
    $c.gus.cfEnableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, btn_pchsItemCd, btn_branchCd]);
  } else {
    $c.gus.cfEnableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
    $c.gus.cfDisableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, btn_pchsItemCd, btn_branchCd]);
  }
  scwin.f_SetGridFormat();
  scwin.f_setCompanyInfo();

  //cfDisableObjects([pu_evid]);
};

