scwin.f_HiddenCheck = function (str, msg) {
  //alert(str.text.trim());
  //alert(str.hidVal);

  if (str.getValue().trim() == "") return true;
  if (str.getValue().trim() != str.options.hidVal) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_038, [msg]);
    //str.SelectAll = "true";
    str.focus();
    return false;
  } else {
    return true;
  }
};

//-------------------------------------------------------------------------
// 체크
//-------------------------------------------------------------------------
scwin.f_Validation = async function () {
  let ret;

  // 사업자번호 체크
  await scwin.f_BizCheck();
  ret = await $c.gus.cfValidate($p, [lc_evidClsCd, lc_deductClsCd, lc_adjmClsCd, ed_slipDt, ed_slipAcctDeptCd, ed_dcAmt, ed_acctCd, ed_acctDeptCd, ed_summary, ed_spplyAmt, ed_vatAmt, ed_crn, ed_mgntEmpNo, ed_adjmClntNo, ed_crnNm, ed_vatDeclarAcctDeptCd, ed_mgntClntNo]);
  if (!ret) return false;
  if (!scwin.f_HiddenCheck(ed_slipAcctDeptCd, "발행부서")) return false;
  if (!scwin.f_HiddenCheck(ed_crn, "사업자번호")) return false;
  if (!scwin.f_HiddenCheck(ed_cardNo, "카드번호")) return false;
  if (!scwin.f_HiddenCheck(ed_acctCd, "계정")) return false;
  if (!scwin.f_HiddenCheck(ed_acctDeptCd, "귀속부서")) return false;
  if (!scwin.f_HiddenCheck(ed_vatDeclarAcctDeptCd, "부가세관리부서")) return false;
  if (!scwin.f_HiddenCheck(ed_mgntEmpNo, "사원번호")) return false;
  if (!scwin.f_HiddenCheck(ed_mgntClntNo, "거래처")) return false;

  // 법인카드나 개인카드 시  카드번호 정산처필수
  if (lc_evidClsCd.getValue() == "40" || lc_evidClsCd.getValue() == "50") {
    ret = $c.gus.cfValidate($p, [ed_cardNo]);
    if (!ret) return false;
  }

  //증빙구분이 세금계산서일때 거래처 필수
  if (lc_evidClsCd.getValue() == "10") {
    ret = $c.gus.cfValidate($p, [ed_mgntEmpNo]);
    if (!ret) return false;
  }

  // 미지급이나 법인카드시 정산처 필수,외상매입금도 추가 ( 2007.02.05 법인카드일때 정산처 필수 )
  // 선급금일때 정산처 필수 (2016.10.24)
  if ((lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_NOPAY_COST || lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_NOPAY || lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_AP || lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_COR_CARD || lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_PREPAY) && ed_adjmClntNo.getValue().trim() == "") {
    $c.gus.cfEnableObjects($p, [ed_adjmClntNo]);
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("정산처"));
    if (!scwin.f_HiddenCheck(ed_adjmClntNo, "정산처")) return false;
    ed_adjmClntNo.focus();
    return false;
  }

  // 전도금일경우 전도금 집행부서는 필수
  if (lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_ADVANCED && ed_adjmAcctDeptCd.getValue().trim() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("정산방법이 전도금일 경우 귀속부서의 전도금 집행부서"));
    ed_acctDeptCd.focus();
    return false;
  }
  ret = await $c.gus.cfIsAfterDate($p, ed_mgntTermStDt.getValue().trim(), ed_mgntTermEndDt.getValue().trim());
  if (!ret) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ed_mgntTermStDt.focus();
    return false;
  }

  //금액체크(금액=공급금액+부가세액)
  let amt = Number(ed_spplyAmt.getValue().trim()) + Number(ed_vatAmt.getValue().trim());
  if (Number(amt) > Number(scwin.txt_limitAmt)) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_048, Array("금액(공급금액+부가세액)", "한도액(" + scwin.txt_limitAmt + ") "));
    ed_spplyAmt.focus();
    return false;
  }

  // 계정코드와 부서체크
  // 1^자산,2^부채,3^자본,4^수익,5^비용,6^원가
  // 비용구분 : 01^원가,02^판관비,03^원가+판관비
  if (scwin.txt_costClsCd == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_018, Array("부서에 따른 비용구분코드", "비용구분코드를 등록"));
    ed_acctDeptCd.focus();
    return false;
  }
  if (scwin.txt_costClsCd.trim() == "01" && scwin.txt_acctClsCd.trim() != "6" && ed_acctCd.getValue() != "6120220") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_061, Array("원가부서", "원가계정"));
    ed_acctCd.focus();
    return false;
  }
  if (scwin.txt_costClsCd == "02" && scwin.txt_acctClsCd.trim() != "5" && ed_acctCd.getValue() != "6120220") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_061, Array("판관비부서", "비용계정"));
    ed_acctCd.focus();
    return false;
  }
  if (scwin.txt_costClsCd == "03" && scwin.txt_acctClsCd.trim() != "6" && scwin.txt_acctClsCd.trim() != "5" && ed_acctCd.getValue() != "6120220") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_055, Array("부서와 계정"));
    ed_acctCd.focus();
    return false;
  }

  // 법인카드일경우 증빙종류가 법인카드
  if (lc_adjmClsCd.getValue() == ACConstants.ADJM_MTHDCD_COR_CARD && lc_evidClsCd.getValue() != "40") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_061, Array("정산방법이 법인카드일 경우 증빙종류는 법인카드"));
    return false;
  }
  if (lc_evidClsCd.getValue() == "40" && lc_adjmClsCd.getValue() != ACConstants.ADJM_MTHDCD_COR_CARD) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_061, Array("증빙종류가 법인카드일 경우 정산방법은 법인카드"));
    return false;
  }
  if (ed_paymentPrd.getValue().trim() == "" && chk_giro.getValue() == true) {
    $c.gus.cfAlertMsg($p, "지로 납부기한을 입력해 주십시오.");
    ed_paymentPrd.focus();
    return false;
  }

  // 차량 유지비 계정일 경우 업무용차량구분 필수
  if (ed_acctCd.getValue() == '4203600' || ed_acctCd.getValue() == '4203610' || ed_acctCd.getValue() == '4203620' || ed_acctCd.getValue() == '4203640' || ed_acctCd.getValue() == '4203660' || ed_acctCd.getValue() == '5002100' || ed_acctCd.getValue() == '5002110' || ed_acctCd.getValue() == '5002120' || ed_acctCd.getValue() == '5002140' || ed_acctCd.getValue() == '5002160') {
    if (lc_busiCarYn.getValue() == 0) {
      $c.gus.cfAlertMsg($p, "계정코드가 차량유지비 계정일 경우 업무용차량여부를 'Y' 또는 'N' 또는  '개인차량' 을 선택하십시오.");
      lc_busiCarYn.focus();
      return false;
    }
  }

  //업무용차량여부 체크(2017.05.23 개인차량 추가)
  if (lc_busiCarYn.getValue() == 1 || lc_busiCarYn.getValue() == 3) {
    if (lc_expenseCd.getValue() == "") {
      $c.gus.cfAlertMsg($p, "비용구분을 선택하여 주십시오.");
      lc_expenseCd.focus();
      return false;
    }
    if (ed_vehcleNo.getValue() == "") {
      $c.gus.cfAlertMsg($p, "차량번호를 선택하여 주십시오.");
      ed_vehcleNo.focus();
      return false;
    }
  }
  return true;
};

