scwin.udc_slipAcctDeptCd_cb = function (rtnList) {
  scwin.f_resultPopEd(ed_slipAcctDeptCd, ed_slipAcctDeptNm, rtnList);
  if (rtnList != null) {
    if (rtnList[4] != "000" || rtnList[4] == null) {
      if (scwin.vCoCd != rtnList[4]) {
        $c.win.alert($p, "소속 자회사 사람만 전표를 입력할수 있습니다");
        ed_slipAcctDeptCd.setValue("");
        ed_slipAcctDeptNm.setValue("");
        ed_slipAcctDeptCd.focus();
        return;
      }
    }
    if (rtnList[2] == "00130") {
      $c.gus.cfDisableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
      $c.gus.cfEnableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, btn_pchsItemCd, btn_branchCd]);
      branchTr.show();
    } else {
      $c.gus.cfEnableObjects($p, [ed_acctCd, ed_acctNm, ed_acctDeptCd, ed_acctDeptNm, btn_acctCd, btn_acctDeptCd]);
      $c.gus.cfDisableObjects($p, [ed_pchsItemCd, ed_branchCd, ed_pchsItemNm, ed_branchNm, btn_pchsItemCd, btn_branchCd]);
      branchTr.hide();
      ed_pchsItemCd.setValue("");
      ed_pchsItemNm.setValue("");
      ed_branchCd.setValue("");
      ed_branchNm.setValue("");
    }
    if (scwin.vBizDomCd == null || scwin.vBizDomCd == "") {
      if (rtnList[3] == "210" || rtnList[3] == "220" || rtnList[3] == "242") {
        scwin.gBizDomCdClsCd = "1";
      } else {
        scwin.gBizDomCdClsCd = "0";
      }
    } else {
      if (!(ed_acctCd.getValue() == null || ed_acctCd.getValue() == "")) {
        $c.gus.cfAlertMsg($p, "발행부서를 수정할 경우에는 계정코드를 재입력하셔야 합니다.");
        ed_acctCd.setValue("");
        ed_acctCd.options.hidVal = "";
        ed_acctNm.setValue("");
        ed_pchsItemCd.setValue("");
        ed_pchsItemCd.options.hidVal = "";
        ed_pchsItemNm.setValue("");
      }
    }
    scwin.vUpperAcctDeptCd = rtnList[2];
    scwin.vBizDomCd = rtnList[3];
    scwin.varCostClsCd = "";

    //자회사 회계 시스템 추가에 따라 , 발행 부서 선택시, 회사 코드와, 회사 구분 코드를 넘김.    
    scwin.txtCoCd = rtnList[4]; //회사코드 
    scwin.txtCoClsCd = rtnList[5]; //회사구분코드    ;  
  }
  scwin.f_SetGridFormat();
  scwin.f_setInitObj();
  lc_adjmClsCd.setValue("2");
};

