scwin.f_VatDeclarAcctDeptCd = function (str) {
  if (ed_acctDeptCd.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, Array("귀속부서"));
    ed_vatDeclarAcctDeptCd.setValue("");
    ed_acctDeptCd.focus();
    return;
  }
  let param = "," + ed_acctDeptCd.getValue() + ",1";
  let sqlID = "";
  let check = "";
  let popTemp = "";
  // popup 버튼 눌렀을경우
  if (str == "1") {
    param = ",,1," + scwin.txtCoCd + "," + scwin.txtCoClsCd + "," + ed_txnDt.getValue().substring(0, 4);
    check = "F";
    sqlID = "retrieveVatDeclarAcctDeptCd";
    popTemp = "";
    // 부서에서 넘어왔을 경우
  } else if (str == "2") {
    param = "," + ed_acctDeptCd.getValue() + "," + scwin.txtCoCd + "," + scwin.txtCoClsCd + "," + ed_txnDt.getValue().substring(0, 4);
    check = "T";
    ed_vatDeclarAcctDeptCd.setValue("");
    sqlID = "retrieveVatDeclarAcctDeptCdAcctDeptCd";
    popTemp = "ZZ";
    // 부가세관리부서에 값을넣고 명을 찾을 경우
  } else if (str == "3") {
    param = ",,1," + scwin.txtCoCd + "," + scwin.txtCoClsCd + "," + ed_txnDt.getValue().substring(0, 4);
    check = "T";
    sqlID = "retrieveVatDeclarAcctDeptCd";
    popTemp = "";
  }
  udc_vatDeclarAcctDeptCd.setSelectId(sqlID);
  udc_vatDeclarAcctDeptCd.cfCommonPopUp(scwin.udc_vatDeclarAcctDeptCd_cb, ed_vatDeclarAcctDeptCd.getValue().trim(), popTemp, check, null, null, null, null, param, null, null, null, null, null, 'F',
  //전체검색
  null, null // pNoDataCloseTF - 'T'이면 데이터 0건 시 팝업이 열리지 않으므로 null 처리
  );
};

